import{_ as u,c as r,o as _,b as t,j as p,a,w as s,d,u as o,p as f}from"./index-JeLFhG-q.js";const h={class:"about-container"},m={class:"container"},b={class:"about-carousel"},g={class:"carousel-item"},w={class:"image-slot"},x={class:"carousel-item"},j={class:"image-slot"},V={class:"carousel-item"},y={class:"image-slot"},A={__name:"AboutView",setup(B){const i="/sanning-vocational-school/";return(N,e)=>{const n=d("el-icon"),c=d("el-image"),l=d("el-carousel-item"),v=d("el-carousel");return _(),r("div",h,[t("div",m,[e[3]||(e[3]=t("h2",null,"学校简介",-1)),t("div",b,[a(v,{interval:3e3,type:"card",height:"400px",arrow:"hover"},{default:s(()=>[a(l,null,{default:s(()=>[t("div",g,[a(c,{src:o(i)+"images/zhixiaodamen.jpg",fit:"cover",style:{width:"100%",height:"100%"}},{error:s(()=>[t("div",w,[a(n,null,{default:s(()=>[a(o(f))]),_:1}),e[0]||(e[0]=t("span",null,"学校环境图片",-1))])]),_:1},8,["src"])])]),_:1}),a(l,null,{default:s(()=>[t("div",x,[a(c,{src:o(i)+"images/shixunlou.jpg",fit:"cover",style:{width:"100%",height:"100%"}},{error:s(()=>[t("div",j,[a(n,null,{default:s(()=>[a(o(f))]),_:1}),e[1]||(e[1]=t("span",null,"实训设备图片",-1))])]),_:1},8,["src"])])]),_:1}),a(l,null,{default:s(()=>[t("div",V,[a(c,{src:o(i)+"images/diannaojifang.jpg",fit:"cover",style:{width:"100%",height:"100%"}},{error:s(()=>[t("div",y,[a(n,null,{default:s(()=>[a(o(f))]),_:1}),e[2]||(e[2]=t("span",null,"培训课堂图片",-1))])]),_:1},8,["src"])])]),_:1})]),_:1})]),e[4]||(e[4]=p('<div class="full-intro" data-v-2e2af4fd><section class="about-section" data-v-2e2af4fd><h3 data-v-2e2af4fd>学校概况</h3><div class="about-content" data-v-2e2af4fd><p data-v-2e2af4fd>枝江三宁职业技术学校（以下简称三宁职校）系政府人力资源与社会保障部门批准设立，湖北三宁化工股份有限公司投资建设的培训学校，学校创办于2013年4月，位于枝江市马家店前进路17号。</p></div></section><section class="about-section" data-v-2e2af4fd><h3 data-v-2e2af4fd>资质认证</h3><div class="about-content" data-v-2e2af4fd><p data-v-2e2af4fd>三宁职校系湖北省安全生产教育培训机构、湖北省特种设备作业人员考试点，枝江化工安全技能实训基地、全国大学生实训实习基地、宜昌市产业工人培训基地，2023年1月被授予全国首批石油和化工行业安全技能实训基地。</p></div></section><section class="about-section" data-v-2e2af4fd><h3 data-v-2e2af4fd>硬件设施</h3><div class="about-content" data-v-2e2af4fd><p data-v-2e2af4fd>三宁职校占地50余亩，建筑面积31190平米，学校设置教学楼、实训大楼、办公楼、公寓住宿楼、食堂、运动场等功能分区，布局合理；建有化工工艺、机械维修、高低压电工、化工仪表自动化、金属焊接与热切割、特殊作业、安全防护和体验装置等10多个专业实训室和训练场所；拥有多媒体、OTS仿真、智慧屏等先进教学设施；学校运动场、文体健身设施、无线网络，宿舍空调、热水供应等配套设施一应俱全。</p></div></section><section class="about-section" data-v-2e2af4fd><h3 data-v-2e2af4fd>培训项目</h3><div class="about-content" data-v-2e2af4fd><p data-v-2e2af4fd>三宁职校常年开设单位负责人、安全管理人员、电工、焊工、高处、危化等特种作业人员取证与复审培训班；开展锅炉、水处理、压力容器等特种设备操作员培训考试，开展消防值班员培训。同时为企业新入职人员、在岗员工开展钳工、电工、仪表工、焊工、化工操作工的技能提升培训和等级认定，还常年开设内训师、数字化工具应用、AI应用、Office办公技能提升等公共课程，为广大职场人职业技能提升保驾护航。</p></div></section><section class="about-section" data-v-2e2af4fd><h3 data-v-2e2af4fd>技能大赛</h3><div class="about-content" data-v-2e2af4fd><p data-v-2e2af4fd>三宁职校被授予技能大赛实训基地，多次承办省市级叉车、化工总控工、仪器仪表工、电工、钳工、化学检验工技能大赛，并得到各级主办单位的高度评价。</p></div></section><section class="about-section" data-v-2e2af4fd><h3 data-v-2e2af4fd>发展规划</h3><div class="about-content" data-v-2e2af4fd><p data-v-2e2af4fd>三宁职校以赋能三宁公司和姚家港化工园区员工为主业，本着立足宜昌，辐射湖北的思路，积极对外拓展培训与相关业务。近年来为宜昌市东部产业新区、孝感东城和盐化工业园、潜江工业园、荆州松滋工业园等园区和机构提供了多工种的安全培训、专业技能提升和取证服务。未来，三宁职校将致力于打造湖北一流、行业知名、化工专业特色显著的培训学校，为化工行业发展和地方经济建设做出更大的贡献。</p></div></section></div>',1))])])}}},k=u(A,[["__scopeId","data-v-2e2af4fd"]]);export{k as default};
